C の書き方C++ の書き方 <pre><code>/* printf を使うためのヘッダ */
#include &lt;stdio.h&gt;
/* toupper を使うためのヘッダ */
#include &lt;ctype.h&gt;

/* argc: 引数の個数 */
/* argv: 引数文字列の配列 */
int main(int argc, char **argv)
{
    /* ループ用の変数を宣言 */
    /* (C89 では先頭にまとめる必要あり) */
    int i, j;
    /* argc == 1 = プログラム名のみ */
    if (argc == 1)
    {
        /* printf: C の標準出力関数 */
        /* \n で改行まで含めて出力 */
        printf("* LOUD AND UNBEARABLE FEEDBACK NOISE *\n");
        /* 正常終了 (return 0) */
        return (0);
    }
    /* argv[1] から順番に処理 */
    for (i = 1; i &lt; argc; i++)
        /* argv[i][j] が '\0' でない間 */
        for (j = 0; argv[i][j]; j++)
            /* toupper: 小文字を大文字へ変換 */
            /* %c: 1文字として出力 */
            printf("%c", toupper(argv[i][j]));
    /* 最後に改行を出力 */
    printf("\n");
    return (0);
}
</code></pre> <pre><code>// std::cout を使うためのヘッダ
#include &lt;iostream&gt;
// std::toupper を使うためのヘッダ
// (C の &lt;ctype.h&gt; の C++ 版)
#include &lt;cctype&gt;

// argc: 引数の個数
// argv: 引数文字列の配列
int main(int argc, char **argv)
{
    // argc == 1 = プログラム名のみ
    if (argc == 1)
    {
        // std::cout &lt;&lt; で画面に出力
        // &lt;&lt; は「これを送る」の意味
        // std::endl は「改行+フラッシュ」
        std::cout &lt;&lt; "* LOUD AND UNBEARABLE FEEDBACK NOISE *"
                  &lt;&lt; std::endl;
        return (0);
    }
    // argv[1] から順番に処理
    // int i を for の中で宣言できる
    // (C89 と違う C++ の特徴)
    for (int i = 1; i &lt; argc; i++)
        // argv[i][j] が '\0' でない間
        for (int j = 0; argv[i][j]; j++)
            // std::toupper: 小文字→大文字変換
            // (char) キャストで文字として出す
            // (付けないと数字で出てしまう)
            std::cout &lt;&lt; (char)std::toupper(argv[i][j]);
    // 最後に改行を出力
    std::cout &lt;&lt; std::endl;
    return (0);
}
</code></pre> <p>何が変わった？</p> C C++ 一言で言うと <code>#include &lt;stdio.h&gt;</code> <code>#include &lt;iostream&gt;</code> ヘッダが変わった <code>#include &lt;ctype.h&gt;</code> <code>#include &lt;cctype&gt;</code> C++ 版ヘッダ <code>printf("text")</code> <code>std::cout &lt;&lt; "text"</code> 出力方法が変わった <code>printf("\n")</code> <code>std::cout &lt;&lt; std::endl</code> 改行の書き方 <code>toupper(c)</code> <code>std::toupper(c)</code> <code>std::</code> が付いた

megaphone.cpp<pre><code>// ─── ヘッダ ───
// iostream: 画面に文字を出すための道具が入っている
#include &lt;iostream&gt;
// cctype: 文字を大文字にする関数が入っている
#include &lt;cctype&gt;

int main(int argc, char **argv)
{
    // ── 引数がない場合 ──
    // argc == 1 は「プログラム名だけ」の意味
    // （argv[0] がプログラム名なので）
    if (argc == 1)
    {
        // std::cout &lt;&lt; で画面に文字を出す
        // std::endl は「改行して出力を確定」
        std::cout
            &lt;&lt; "* LOUD AND UNBEARABLE FEEDBACK NOISE *"
            &lt;&lt; std::endl;
        return (0);
    }

    // ── 引数がある場合 ──
    // argv[1] から argv[argc-1] まで処理する
    for (int i = 1; i &lt; argc; i++)
    {
        // 各引数の文字を1文字ずつ処理
        for (int j = 0; argv[i][j]; j++)
        {
            // toupper: 小文字→大文字に変換
            // (char) を付けないと数字として出る
            char c = (char)std::toupper(argv[i][j]);
            std::cout &lt;&lt; c;
        }
    }
    // 最後に改行を出す
    std::cout &lt;&lt; std::endl;
    return (0);
}
</code></pre>

Contact.hpp<pre><code>// ── インクルードガード ──
// 同じヘッダを2回読み込まないようにする
#ifndef CONTACT_HPP
#define CONTACT_HPP

#include &lt;string&gt;

class Contact
{
// ── private: 外から直接触れないデータ ──
private:
    // 先頭の _ は「private だよ」の印
    // 42 の慣習（ルールではない）
    std::string _firstName;
    std::string _lastName;
    std::string _nickname;
    std::string _phoneNumber;
    std::string _darkestSecret;

// ── public: 外から使える関数 ──
public:
    // コンストラクタ（作るとき自動で呼ばれる）
    Contact();
    // デストラクタ（消えるとき自動で呼ばれる）
    ~Contact();

    // getter: 読み取り窓口
    // 末尾の const = 「変更しません」の約束
    std::string getFirstName() const;
    std::string getLastName() const;
    std::string getNickname() const;
    std::string getPhoneNumber() const;
    std::string getDarkestSecret() const;

    // setter: 書き込み窓口
    // const std::string &amp; = コピーしない参照渡し
    void setFirstName(
        const std::string &amp;value);
    void setLastName(
        const std::string &amp;value);
    void setNickname(
        const std::string &amp;value);
    void setPhoneNumber(
        const std::string &amp;value);
    void setDarkestSecret(
        const std::string &amp;value);

    // 空かどうか判定する関数
    bool isEmpty() const;
};

#endif
</code></pre>

