C の書き方C++ の書き方 <pre><code>/* snprintf 用のヘッダ */
#include &lt;stdio.h&gt;

/* ── バッファを用意 ── */
/* 256文字固定、溢れたら切り捨て */
char buf[256];

/* ── snprintf で整形 ── */
/* snprintf: 文字列を整形してバッファに入れる */
/* 引数: 出力先、最大サイズ、書式、値 */
/* %10s = 幅10、右寄せで文字列を入れる */
snprintf(buf, 256,
    "%10s|%10s|", name1, name2);

/* ── 画面に出力 ── */
/* printf: C の標準出力関数 */
printf("%s\n", buf);
</code></pre> <pre><code>// setw / right を使うためのヘッダ
#include &lt;iomanip&gt;

// setw(10) = 次の出力を幅10で表示
//           (printf の %10s と同じ効果)
// right    = 右寄せ指定
std::cout
    &lt;&lt; std::setw(10)  // 幅10を指定
    &lt;&lt; std::right     // 右寄せ
    &lt;&lt; name1          // 1つ目の値
    &lt;&lt; "|"            // 区切り文字
    &lt;&lt; std::setw(10)  // 再び幅10
    &lt;&lt; std::right     // 再び右寄せ
    &lt;&lt; name2          // 2つ目の値
    &lt;&lt; "|"            // 区切り文字
    &lt;&lt; std::endl;     // 改行+フラッシュ
</code></pre> マニピュレータ 効果 <code>std::setw(N)</code> 次の出力を幅Nで表示 <code>std::right</code> 右寄せ <code>std::left</code> 左寄せ <p><code>setw</code> は1回しか効かない</p> <p><code>setw(10)</code> は 次の <code>&lt;&lt;</code> 1回だけ に適用されます。 列ごとに毎回書き直す必要があります。</p> <pre><code>// NG: a だけ幅10、b と c は幅なし
std::cout &lt;&lt; std::setw(10)
          &lt;&lt; a &lt;&lt; b &lt;&lt; c;

// OK: 全部に幅10
std::cout &lt;&lt; std::setw(10) &lt;&lt; a
          &lt;&lt; std::setw(10) &lt;&lt; b
          &lt;&lt; std::setw(10) &lt;&lt; c;
</code></pre>

main.cpp<pre><code>#include "PhoneBook.hpp"
#include &lt;iostream&gt;

// 空入力を許さず再入力させるヘルパー
// static = このファイル内でだけ使える
static std::string readField(
    const std::string &amp;prompt)
{
    std::string input;

    while (true)
    {
        std::cout &lt;&lt; prompt;
        // getline で1行読む
        // EOF(Ctrl+D) なら空文字を返す
        if (!std::getline(std::cin, input))
            return "";
        // 空でなければ OK
        if (!input.empty())
            return input;
        std::cout
            &lt;&lt; "Field cannot be empty."
            &lt;&lt; std::endl;
    }
}

int main(void)
{
    // PhoneBook オブジェクトをスタック上に生成
    // → コンストラクタが自動で走る
    PhoneBook   book;
    std::string command;

    while (true)
    {
        std::cout
            &lt;&lt; "Enter command "
            &lt;&lt; "(ADD, SEARCH, EXIT): ";

        // 1行読む（EOF なら抜ける）
        if (!std::getline(
                std::cin, command))
            break;

        // std::string は == で比較できる
        // strcmp は不要！
        if (command == "ADD")
            doAdd(book);
        else if (command == "SEARCH")
            doSearch(book);
        else if (command == "EXIT")
            break;
        // それ以外は無視してループに戻る
    }
    // } を抜けると book のデストラクタが
    // 自動で呼ばれる
    return 0;
}
</code></pre> <p>なぜ動的メモリ確保を使わないの？</p> <p>subject で「最大8件」と決まっているので、 <code>Contact _contacts[8]</code> の固定長配列で十分です。</p> <p><code>new</code> / <code>delete</code> を使う必要がなく、 メモリリークの心配もありません。</p> <p>9件目以降はリングバッファ方式で対応します。</p> <pre><code>// リングバッファ: 周回するインデックス
// 0 → 1 → 2 ... → 7 → 0 に戻る
_oldest = (_oldest + 1) % 8;
</code></pre>

C の書き方C++ の書き方 <pre><code>/* printf 用のヘッダ */
#include &lt;stdio.h&gt;
/* malloc / free 用のヘッダ */
#include &lt;stdlib.h&gt;
/* strcpy 用のヘッダ */
#include &lt;string.h&gt;

/* ── 構造体を定義 ── */
/* C には class がないので struct を使う */
typedef struct s_zombie {
    /* 名前を格納する50文字の配列 */
    char name[50];
} t_zombie;

/* ── ヒープに作る関数 ── */
t_zombie *new_zombie(char *name) {
    /* ポインタ変数を用意 */
    t_zombie *z;
    /* malloc で必要なバイト数を確保 */
    /* sizeof(t_zombie) = 構造体のサイズ */
    z = malloc(sizeof(t_zombie));
    /* 名前を文字列コピー */
    /* (C++ なら自動だがCは手動) */
    strcpy(z-&gt;name, name);
    /* 確保したポインタを返す */
    return z;
}

/* ── スタックに作る関数 ── */
void random_chump(char *name) {
    /* 変数としてスタック上に確保 */
    /* (malloc 不要、自動破棄される) */
    t_zombie z;
    /* 名前をコピー */
    strcpy(z.name, name);
    /* 名前と叫び声を出力 */
    printf("%s: BraiiiiiiinnnzzzZ...\n",
           z.name);
    /* 関数終了 → z が自動で消える */
    /* (スタックの特徴) */
}

int main(void) {
    /* ヒープに作る */
    t_zombie *z = new_zombie("Heap");
    /* ヒープゾンビを叫ばせる */
    printf("%s: BraiiiiiiinnnzzzZ...\n",
           z-&gt;name);
    /* スタック版を呼ぶ (中で自動破棄) */
    random_chump("Stack");
    /* ヒープのメモリを手動で解放 */
    /* 忘れるとメモリリーク！ */
    free(z);
    return 0;
}
</code></pre> <pre><code>// cout 用のヘッダ
#include &lt;iostream&gt;
// std::string 用のヘッダ
#include &lt;string&gt;

// ── Zombie クラスの定義 ──
// class は「データ + 関数」をまとめる箱
class Zombie {
private:
    // 名前 (外から直接触れない)
    // std::string は自動でサイズ管理
    // (Cの char[50] の進化版)
    std::string _name;

public:
    // ── コンストラクタ ──
    // new や Zombie z("x") の時に
    // 自動で呼ばれる
    // : _name(name) は「初期化子リスト」
    // → _name に name を代入する書き方
    Zombie(std::string name)
        : _name(name) {}

    // ── デストラクタ ──
    // delete や関数終了時に
    // 自動で呼ばれる
    // 後片付けを書く場所
    ~Zombie(void) {
        std::cout &lt;&lt; _name
            &lt;&lt; " has been destroyed"
            &lt;&lt; std::endl;
    }

    // ── メンバ関数 announce ──
    // クラスに属する関数
    void announce(void) {
        std::cout &lt;&lt; _name
            &lt;&lt; ": BraiiiiiiinnnzzzZ..."
            &lt;&lt; std::endl;
    }
};

// ── ヒープに作る関数 ──
// new: メモリ確保 + コンストラクタ呼び出し
//      を1発でやる
// (C の malloc + init を合体させた命令)
Zombie *newZombie(std::string name) {
    return new Zombie(name);
}

// ── スタックに作る関数 ──
void randomChump(std::string name) {
    // new を使わない = スタック上に確保
    // ここでコンストラクタが自動で呼ばれる
    Zombie z(name);
    // z.announce() で叫ぶ
    // (z は変数なので . でアクセス)
    z.announce();
    // 関数終了 → z のデストラクタが
    // 自動で呼ばれる (スタックの特徴)
}

int main(void) {
    // ヒープに作る
    // z はポインタ
    Zombie *z = newZombie("Heap");
    // z-&gt;announce() で叫ぶ
    // (z はポインタなので -&gt; でアクセス)
    z-&gt;announce();
    // スタック版を呼ぶ
    // (中で作って中で自動破棄)
    randomChump("Stack");
    // delete: デストラクタ呼び出し +
    //         メモリ解放 を1発でやる
    // (C の cleanup + free を合体)
    delete z;
    return 0;
}
</code></pre> <p>何が変わった？</p> C C++ 一言で言うと <code>malloc</code> + 手動初期化 <code>new</code> 確保+初期化が一発 <code>free</code> <code>delete</code> 破棄処理+解放が一発 構造体 (<code>struct</code>) クラス (<code>class</code>) データと関数をまとめられる <code>printf</code> <code>std::cout</code> 出力方法が変わった

Zombie.hpp<pre><code>// ── インクルードガード ──
// 同じヘッダが2回読まれるのを防ぐ
#ifndef ZOMBIE_HPP
#define ZOMBIE_HPP

// string: 文字列を使うために必要
#include &lt;string&gt;
// iostream: 画面に文字を出すために必要
#include &lt;iostream&gt;

// ── Zombie クラスの定義 ──
class Zombie {
private:
    // ゾンビの名前（外から直接触れない）
    std::string _name;

public:
    // コンストラクタ: ゾンビを作る時に呼ばれる
    Zombie(std::string name);
    // デストラクタ: ゾンビが消える時に呼ばれる
    ~Zombie(void);
    // 「うおおお」と叫ぶ関数
    void announce(void);
};

// ── クラスの外の関数 ──
// ヒープにゾンビを作る関数
Zombie *newZombie(std::string name);
// スタックにゾンビを作る関数
void    randomChump(std::string name);

#endif
</code></pre>

Zombie.cpp<pre><code>#include "Zombie.hpp"

// ── コンストラクタ ──
// : _name(name) は「初期化子リスト」
// コンストラクタの本体に入る前に
// _name を初期化する書き方
Zombie::Zombie(std::string name)
    : _name(name) {
}

// ── デストラクタ ──
// ゾンビが消える時に自動で呼ばれる
// 「誰が消えたか」を画面に出す
Zombie::~Zombie(void) {
    std::cout &lt;&lt; _name
              &lt;&lt; " has been destroyed"
              &lt;&lt; std::endl;
}

// ── announce ──
// ゾンビの名前と叫び声を表示
void Zombie::announce(void) {
    std::cout &lt;&lt; _name
              &lt;&lt; ": BraiiiiiiinnnzzzZ..."
              &lt;&lt; std::endl;
}
</code></pre> <p>初期化子リストって何？</p> <p><code>: _name(name)</code> の部分を 初期化子リスト と言います。</p> <pre><code>// ✅ 初期化子リスト（おすすめ）
Zombie::Zombie(std::string name)
    : _name(name) {
}

// △ 本体で代入（動くが効率が少し悪い）
Zombie::Zombie(std::string name) {
    _name = name;
}
</code></pre> <p>初期化子リストは const メンバ や 参照メンバ には 必須 です。 常にこの書き方を使う癖をつけましょう。</p>

newZombie.cpp<pre><code>#include "Zombie.hpp"

// ── ヒープにゾンビを作る ──
// new で作る → ポインタを返す
// 呼んだ側が delete する責任を持つ
Zombie *newZombie(std::string name) {
    return new Zombie(name);
}
</code></pre> <p>なぜ <code>new</code> で作るのか？</p> <p>関数の 外でも使いたい からです。</p> <p>スタックに作った変数は、関数が終わると消えます。 消えた変数のアドレスを返すと ダングリングポインタ （もう存在しないものを指すポインタ）になって危険です。</p> <pre><code>// ダメな例: スタック変数のアドレスを返す
Zombie *bad() {
    Zombie z("local");
    return &amp;z;
    // z は関数終了で消える
    // → 返したポインタは無効！
}

// 良い例: ヒープに作って返す
Zombie *good() {
    return new Zombie("heap");
    // ヒープのオブジェクトは
    // delete するまで消えない
}
</code></pre>

randomChump.cpp<pre><code>#include "Zombie.hpp"

// ── スタックにゾンビを作る ──
// 関数の中だけで使って、
// 関数が終わると自動で消える
void randomChump(std::string name) {
    // スタック上に Zombie を作る
    // new を使わないのがポイント
    Zombie zombie(name);
    // 叫ばせる
    zombie.announce();
}
// ← ここで zombie は自動的に破棄される
// デストラクタが呼ばれる
// delete は不要！
</code></pre> <p>なぜスタックで十分なのか？</p> <p><code>randomChump()</code> の中でゾンビを作って叫ばせるだけ。 関数の外にゾンビを持ち出さない ので、 スタックで十分です。</p> <p>スタックなら <code>delete</code> を書く必要がないので、 メモリリークの心配もゼロ です。</p>

main.cpp<pre><code>#include "Zombie.hpp"

int main(void) {
    // (1) ヒープにゾンビを作る
    // new で作るのでポインタが返ってくる
    Zombie *heap = newZombie("HeapZombie");

    // (2) ポインタ経由で叫ばせる
    // ポインタなので -&gt; を使う
    heap-&gt;announce();

    // (3) スタックにゾンビを作る
    // 関数の中で作って叫んで自動破棄
    randomChump("StackZombie");

    // (4) ヒープゾンビを手動で解放
    // これを忘れるとメモリリーク！
    delete heap;

    return 0;
}
</code></pre>

C の書き方C++ の書き方 <pre><code>/* printf 用のヘッダ */
#include &lt;stdio.h&gt;
/* malloc / free 用のヘッダ */
#include &lt;stdlib.h&gt;
/* sprintf を使う時もこのヘッダ */
#include &lt;string.h&gt;

/* ── 構造体を定義 ── */
/* 名前だけ持つ単純な構造体 */
typedef struct s_zombie {
    /* 50文字までの名前 */
    char name[50];
} t_zombie;

/* ── N体をまとめて確保する関数 ── */
t_zombie *zombie_horde(int n,
                       char *name) {
    /* ループ変数 */
    int i;
    /* 配列の先頭ポインタ */
    t_zombie *arr;
    /* N個分のメモリを一括で確保 */
    /* n * sizeof(...) が合計バイト数 */
    arr = malloc(n * sizeof(t_zombie));
    /* 各要素を手動で初期化 */
    /* (C++ ならコンストラクタが自動) */
    for (i = 0; i &lt; n; i++)
        /* sprintf: 書式付きで文字列生成 */
        /* "H#0", "H#1" ... を作る */
        sprintf(arr[i].name,
                "%s#%d", name, i);
    /* 配列の先頭アドレスを返す */
    return arr;
}

int main(void) {
    /* ループ変数 */
    int i;
    /* 5体まとめて確保 */
    t_zombie *h = zombie_horde(5, "H");
    /* 全員分をループで表示 */
    for (i = 0; i &lt; 5; i++)
        /* h[i].name で i 番目の名前を取得 */
        printf("%s: Brainz...\n",
               h[i].name);
    /* 配列全体をまとめて解放 */
    /* ※ C には delete[] がないので free 1回 */
    free(h);
    return 0;
}
