class Zombie {
private:
    // 名前 (外から直接触れない)
    std::string _name;
public:
    // ── デフォルトコンストラクタ ──
    // 引数なし。new[] で呼ばれる
    Zombie(void) {}
    // ── デストラクタ ──
    // delete[] 時に全要素分呼ばれる
    ~Zombie(void) {
        std::cout &lt;&lt; _name
            &lt;&lt; " has been destroyed"
            &lt;&lt; std::endl;
    }
    // 後から名前を設定するセッター
    void setName(std::string name) {
        _name = name;
    }
    // 叫ぶメンバ関数
    void announce(void) {
        std::cout &lt;&lt; _name
            &lt;&lt; ": BraiiiiiiinnnzzzZ..."
            &lt;&lt; std::endl;
    }
};

// ── N体をまとめて作る関数 ──
Zombie *zombieHorde(int N,
                    std::string name) {
    // new[]: malloc + ループ init を1発
    // デフォルトコンストラクタがN回呼ばれる
    Zombie *h = new Zombie[N];
    // ループで名前を設定
    for (int i = 0; i &lt; N; i++) {
        // stringstream: 文字列と数字を
        // くっつける道具 (sprintf 相当)
        std::stringstream ss;
        // &lt;&lt; で連結 "Horde" + "#" + i
        ss &lt;&lt; name &lt;&lt; "#" &lt;&lt; i;
        // .str() で std::string に変換
        h[i].setName(ss.str());
    }
    // 先頭ポインタを返す
    return h;
}

int main(void) {
    // 作る数
    int N = 5;
    // N体まとめて確保
    Zombie *h = zombieHorde(N, "Horde");
    // 全員叫ばせる
    for (int i = 0; i &lt; N; i++)
        // h[i] で i 番目にアクセス
        // 配列要素なので . を使う
        h[i].announce();
    // delete[]: ループで全員の
    // デストラクタを呼ぶ + free を1発
    delete[] h;
    return 0;
}
