    printf("Address: %p\n", (void *)str);
    /* *ptr で ptr が指す先 = str の値 */
    printf("Address: %p\n", (void *)*ptr);
    /* %s: 文字列を表示する書式指定 */
    printf("Value:   %s\n", str);
    /* *ptr をデリファレンスして値を取得 */
    printf("Value:   %s\n", *ptr);
    return 0;
}
