C の書き方C++ の書き方 <pre><code>/* printf, fprintf, FILE 用のヘッダ */
#include &lt;stdio.h&gt;
/* strlen などの文字列関数用 */
#include &lt;string.h&gt;

int main(int argc, char **argv) {
    /* 引数チェック: 4個必要 */
    if (argc != 4) {
        /* stderr: 標準エラー出力 */
        fprintf(stderr, "Usage...\n");
        return 1;
    }
    /* fopen: ファイルを開く (読み込み) */
    /* 失敗すると NULL を返す */
    FILE *in = fopen(argv[1], "r");
    /* NULL チェック */
    if (!in) {
        fprintf(stderr, "cannot open\n");
        return 1;
    }
    /* 1行を溜めるバッファ (サイズ固定) */
    char buf[1024];
    /* fopen: 書き込みモード "w" で開く */
    FILE *out = fopen("out.replace", "w");
    /* fgets: 1行読む (EOF で NULL) */
    while (fgets(buf, sizeof(buf), in)) {
        /* 自分で strstr + 置換 */
        /* fputs: 文字列を書き込む */
        fputs(buf, out);
    }
    /* fclose: 必ず閉じる */
    /* (忘れるとリークするので手動必須) */
    fclose(in);
    fclose(out);
    return 0;
}
</code></pre> <pre><code>// cerr 用のヘッダ
#include &lt;iostream&gt;
// ifstream / ofstream 用のヘッダ
#include &lt;fstream&gt;
// std::string 用のヘッダ
#include &lt;string&gt;

int main(int argc, char **argv) {
    // 引数チェック
    if (argc != 4) {
        // cerr: 標準エラー出力
        // (C の stderr 相当)
        std::cerr &lt;&lt; "Usage..."
                  &lt;&lt; std::endl;
        return 1;
    }
    // ifstream: 読み用ファイルを開く
    // fopen(..., "r") + fclose 自動化
    std::ifstream in(argv[1]);
    // is_open: ちゃんと開けたか確認
    if (!in.is_open()) {
        std::cerr &lt;&lt; "cannot open"
                  &lt;&lt; std::endl;
        return 1;
    }
    // ofstream: 書き用ファイルを開く
    std::ofstream out("out.replace");
    // 1行を格納する string (可変長)
    std::string line;
    // getline: 1行読む + 改行除去
    // (C の fgets + 改行削除を合体)
    while (std::getline(in, line)) {
        // find + substr で自作置換
        // &lt;&lt; で書き込み (printf の代わり)
        out &lt;&lt; line &lt;&lt; "\n";
    }
    // close 不要 (スコープ抜ける時に
    // デストラクタが自動で呼ぶ = RAII)
    return 0;
}
