main.cpp (replaceAll)<pre><code>// line の中の s1 を全て s2 に置換する
static std::string replaceAll(
    std::string line,
    const std::string &amp;s1,
    const std::string &amp;s2
) {
    std::string result;
    std::size_t pos;

    // ── 空文字列チェック ──
    // s1 が "" だと find が常に 0 を返して
    // 無限ループになるので先に弾く
    if (s1.empty())
        return (line);

    // ── s1 が見つかる間、繰り返し処理 ──
    // find は見つからないと npos を返す
    while ((pos = line.find(s1))
           != std::string::npos)
    {
        // s1 より前の部分を結果に追加
        result += line.substr(0, pos);
        // s1 の代わりに s2 を入れる
        result += s2;
        // 残りの部分を次のループで処理
        line = line.substr(pos + s1.length());
    }

    // もう s1 がない残り部分を追加
    result += line;
    return (result);
}
