s1   = "Hello"
s2   = "Hi"

1回目: pos = 0
       result = "" + "Hi" = "Hi"
       line   = " World Hello"

2回目: pos = 7
       result = "Hi" + " World" + "Hi" = "Hi WorldHi"
       line   = ""

3回目: find は npos → ループ終了
       result += "" → "Hi WorldHi"
