Fixed.cpp<pre><code>// cmath: roundf を使うため
#include &lt;cmath&gt;
#include "Fixed.hpp"

// --- int → Fixed ---
// n を 256 倍して保存する（n &lt;&lt; 8 = n * 256）
// 例: 10 → _value = 2560
Fixed::Fixed(const int n)
    : _value(n &lt;&lt; _fractionalBits)
{
    std::cout
        &lt;&lt; "Int constructor called"
        &lt;&lt; std::endl;
}

// --- float → Fixed ---
// n を 256 倍して四捨五入して保存する
// 例: 42.42 → _value = 10860
Fixed::Fixed(const float n)
    : _value(
        roundf(n * (1 &lt;&lt; _fractionalBits))
    )
{
    std::cout
        &lt;&lt; "Float constructor called"
        &lt;&lt; std::endl;
}

// --- Fixed → float ---
// 保存している値を 256.0 で割って戻す
// static_cast で int→float 変換
float Fixed::toFloat(void) const
{
    return static_cast&lt;float&gt;(this-&gt;_value)
         / (1 &lt;&lt; _fractionalBits);
}

// --- Fixed → int ---
// 保存している値を 256 で割る（&gt;&gt; 8 で切り捨て）
// 例: 10860 &gt;&gt; 8 = 42
int Fixed::toInt(void) const
{
    return this-&gt;_value &gt;&gt; _fractionalBits;
}

// --- operator&lt;&lt; （非メンバ関数）---
// cout &lt;&lt; fixed と書けるようにする
// out を参照で返すことで &lt;&lt;の連鎖が可能
std::ostream &amp;operator&lt;&lt;(
    std::ostream &amp;out,
    const Fixed &amp;fixed)
{
    // toFloat() で float に戻してから出力
    out &lt;&lt; fixed.toFloat();
    // 連鎖用に out を返す
    return out;
}
