/* ── 外積 (自作関数) ── */
/* 2D ベクトルの外積を計算 */
/* 符号で点の左右を判定できる */
float cross(t_point p1, t_point p2,
            t_point p3)
{
    /* 構造体メンバに直接アクセス */
    /* (p2 - p1) × (p3 - p1) を計算 */
    return (p2.x - p1.x)
         * (p3.y - p1.y)
         - (p2.y - p1.y)
         * (p3.x - p1.x);
}

/* ── 三角形判定 (自作関数) ── */
/* 点が三角形の内側か判定 */
int bsp(t_point a, t_point b,
        t_point c, t_point p)
{
    /* 3 辺それぞれの外積を計算 */
    float d1 = cross(a, b, p);
    float d2 = cross(b, c, p);
    float d3 = cross(c, a, p);

    /* 外積が 0 = 辺上 → 外とみなす */
    if (d1 == 0 || d2 == 0 || d3 == 0)
        return 0;

    /* 負の符号があるか (int で代用) */
    int neg = (d1&lt;0) || (d2&lt;0) || (d3&lt;0);
    /* 正の符号があるか */
    int pos = (d1&gt;0) || (d2&gt;0) || (d3&gt;0);
    /* 混在=外側 / 全部同じ=内側 */
    return !(neg &amp;&amp; pos);
}
