bsp.cpp<pre><code>#include "Point.hpp"

// --- 外積のヘルパー関数 ---
// static: このファイル内だけで使える
//         (C の static 関数と同じ)
// 外積 (P1→P2) × (P1→P3) の符号で
// 点が線のどちら側にあるかが分かる
//   正 = 左側, 負 = 右側, 0 = 線上
static Fixed crossProduct(
    Point const p1,
    Point const p2,
    Point const p3)
{
    // ex02 の operator-, operator*, operator-
    // がここで活用される
    return (p2.getX() - p1.getX())
         * (p3.getY() - p1.getY())
         - (p2.getY() - p1.getY())
         * (p3.getX() - p1.getX());
}

// --- bsp 本体 ---
// 三角形 abc の内部に point があれば true
bool bsp(
    Point const a,
    Point const b,
    Point const c,
    Point const point)
{
    // 3 辺それぞれに対して外積を計算
    Fixed d1 = crossProduct(a, b, point);
    Fixed d2 = crossProduct(b, c, point);
    Fixed d3 = crossProduct(c, a, point);

    // 外積が 0 = 辺上 → 仕様で false
    // Fixed(0) は int→Fixed 変換で
    // 一時オブジェクトを作って比較
    if (d1 == Fixed(0)
        || d2 == Fixed(0)
        || d3 == Fixed(0))
        return false;

    // 負の符号があるか？
    bool hasNeg = (d1 &lt; Fixed(0))
               || (d2 &lt; Fixed(0))
               || (d3 &lt; Fixed(0));
    // 正の符号があるか？
    bool hasPos = (d1 &gt; Fixed(0))
               || (d2 &gt; Fixed(0))
               || (d3 &gt; Fixed(0));

    // 負と正が混在 → 外部 → false
    // 全部同じ符号  → 内部 → true
    return !(hasNeg &amp;&amp; hasPos);
}
