ClapTrap.cpp (戦闘メソッド)<pre><code>// ── 攻撃 ──
void ClapTrap::attack(
    const std::string&amp; target)
{
    // (1) HP チェック（死亡中は行動不可）
    if (_hitPoints == 0)
    {
        std::cout &lt;&lt; "ClapTrap " &lt;&lt; _name
            &lt;&lt; " can't attack, "
            &lt;&lt; "no hit points!"
            &lt;&lt; std::endl;
        return;
    }
    // (2) EP チェック（エネルギー切れ）
    if (_energyPoints == 0)
    {
        std::cout &lt;&lt; "ClapTrap " &lt;&lt; _name
            &lt;&lt; " can't attack, "
            &lt;&lt; "no energy points!"
            &lt;&lt; std::endl;
        return;
    }
    // (3) EP を 1 消費
    _energyPoints--;
    // (4) 攻撃メッセージ
    std::cout &lt;&lt; "ClapTrap " &lt;&lt; _name
        &lt;&lt; " attacks " &lt;&lt; target
        &lt;&lt; ", causing " &lt;&lt; _attackDamage
        &lt;&lt; " points of damage!"
        &lt;&lt; std::endl;
}

// ── ダメージを受ける ──
void ClapTrap::takeDamage(
    unsigned int amount)
{
    if (_hitPoints == 0)
    {
        std::cout &lt;&lt; "ClapTrap " &lt;&lt; _name
            &lt;&lt; " is already dead!"
            &lt;&lt; std::endl;
        return;
    }
    // (5) アンダーフロー防止！
    //     amount &gt;= _hitPoints なら 0 にする
    if (amount &gt;= _hitPoints)
        _hitPoints = 0;
    else
        _hitPoints -= amount;
    std::cout &lt;&lt; "ClapTrap " &lt;&lt; _name
        &lt;&lt; " takes " &lt;&lt; amount
        &lt;&lt; " points of damage! HP: "
        &lt;&lt; _hitPoints &lt;&lt; std::endl;
}

// ── 回復 ──
void ClapTrap::beRepaired(
    unsigned int amount)
{
    if (_hitPoints == 0)
    {
        std::cout &lt;&lt; "ClapTrap " &lt;&lt; _name
            &lt;&lt; " can't repair, "
            &lt;&lt; "no hit points!"
            &lt;&lt; std::endl;
        return;
    }
    if (_energyPoints == 0)
    {
        std::cout &lt;&lt; "ClapTrap " &lt;&lt; _name
            &lt;&lt; " can't repair, "
            &lt;&lt; "no energy points!"
            &lt;&lt; std::endl;
        return;
    }
    // EP を 1 消費して HP を回復
    _energyPoints--;
    _hitPoints += amount;
    std::cout &lt;&lt; "ClapTrap " &lt;&lt; _name
        &lt;&lt; " repairs itself for "
        &lt;&lt; amount &lt;&lt; " hit points! HP: "
        &lt;&lt; _hitPoints &lt;&lt; std::endl;
}
</code></pre> <ol> <li>HP チェック — 死亡中は行動不可</li> <li>EP チェック — エネルギー切れでも行動不可</li> <li>EP 消費 — attack と beRepaired は EP を 1 消費、takeDamage は消費しない</li> <li>メッセージ出力 — ダメージ量とターゲット名を表示</li> <li>アンダーフロー防止 — <code>unsigned int</code> なので <code>3 - 5</code> は -2 ではなく約 42 億になる</li> </ol>

