/* 親の初期化を手動で呼ぶ必要あり */
void scav_init(t_scav *s,
               const char *name) {
    /* 忘れると親が初期化されないバグ！ */
    clap_init(&amp;s-&gt;parent, name);
    /* 親のメンバを上書き (parent 経由) */
    s-&gt;parent.hp = 100;
    s-&gt;parent.ep = 50;
    s-&gt;parent.ad = 20;
}

/* ── 子の攻撃関数 (自作) ── */
/* 親のメンバは parent. 経由でアクセス */
void scav_attack(t_scav *s,
                 const char *t) {
    /* EP を 1 消費 (parent 経由) */
    s-&gt;parent.ep--;
    /* printf で出力 */
    printf("ScavTrap attacks %s\n", t);
}
