        &lt;&lt; "DiamondTrap default "
        &lt;&lt; "constructor called"
        &lt;&lt; std::endl;
}

// ── 名前付きコンストラクタ ──
DiamondTrap::DiamondTrap(
    const std::string&amp; name)
    : ClapTrap(name + "_clap_name"),  // (3)
      FragTrap(name),
      ScavTrap(name),
      _name(name)                     // (4)
{
    _hitPoints = 100;
    _energyPoints = 50;
    _attackDamage = 30;
    std::cout
        &lt;&lt; "DiamondTrap constructor "
        &lt;&lt; "called for " &lt;&lt; _name
        &lt;&lt; std::endl;
