DiamondTrap&amp; DiamondTrap::operator=(
    const DiamondTrap&amp; other)
{
    std::cout
        &lt;&lt; "DiamondTrap copy assignment"
        &lt;&lt; " operator called"
        &lt;&lt; std::endl;
