    // これがないと自分の _brain を
    // 消してから参照してしまう
    if (this != &amp;other) {
        // 基底部分の代入を明示呼び出し
        Animal::operator=(other);
        // 旧 Brain を解放 (リーク防止)
        delete _brain;
        // 新しい Brain をディープコピーで作成
        _brain = new Brain(*other._brain);
    }
    return *this;
}

// デストラクタで _brain を解放
// virtual デストラクタなので
// Animal* 経由でも呼ばれる
Dog::~Dog(void) {
    std::cout
        &lt;&lt; "Dog destructor called"
        &lt;&lt; std::endl;
    delete _brain;
}

void Dog::makeSound(void) const {
    std::cout &lt;&lt; "Woof! Woof!" &lt;&lt; std::endl;
}

Brain* Dog::getBrain(void) const {
    return _brain;
}
</code></pre> <p>Cat.cpp もほぼ同じ。違いは <code>_type = "Cat"</code> と <code>makeSound</code> の中身だけ。</p> <p>なぜ <code>delete _brain;</code> でいいのか？</p> <p><code>_brain</code> は <code>new Brain()</code> で作ったので、<code>delete _brain</code> で解放できます。 さらに Brain のデストラクタが自動で呼ばれ、Brain 内部の <code>std::string</code> も 自動で解放されます（RAII）。</p>

