</code></pre> Character.cpp (unequip)<pre><code>// unequip: マテリアを外す
// subject 要件: delete してはいけない!
// → _floor に退避して後でまとめて delete
void Character::unequip(int idx) {
    if (idx &lt; 0 || idx &gt;= 4
        || !_inventory[idx])
        return;
    // _floor に退避
    if (_floorCount &lt; 1024) {
        _floor[_floorCount]
            = _inventory[idx];
        _floorCount++;
    } else {
        // _floor が溢れたら仕方なく delete
        delete _inventory[idx];
    }
    // スロットは空にする
    _inventory[idx] = NULL;
}
