MateriaSource::MateriaSource(void) {
    // 空で初期化
    for (int i = 0; i &lt; 4; i++)
        _learned[i] = NULL;
}

// ディープコピー (clone() を使う)
MateriaSource::MateriaSource(
    const MateriaSource&amp; other
) {
    for (int i = 0; i &lt; 4; i++) {
        if (other._learned[i])
            // 抽象クラスなので clone()
            _learned[i]
                = other._learned[i]-&gt;clone();
        else
            _learned[i] = NULL;
    }
}

MateriaSource&amp; MateriaSource::operator=(
    const MateriaSource&amp; other
) {
    if (this != &amp;other) {
        for (int i = 0; i &lt; 4; i++) {
            delete _learned[i];
            if (other._learned[i])
                _learned[i]
                    = other._learned[i]
                          -&gt;clone();
            else
                _learned[i] = NULL;
        }
    }
    return *this;
}

// 所有している全原本を解放
MateriaSource::~MateriaSource(void) {
    for (int i = 0; i &lt; 4; i++)
        delete _learned[i];
}

// learnMateria:
// 渡されたポインタの所有権を受け取る
void MateriaSource::learnMateria(
    AMateria* m
) {
    if (!m)
        return;
    for (int i = 0; i &lt; 4; i++) {
        if (!_learned[i]) {
            _learned[i] = m;  // 原本を保存
            return;
        }
    }
    // 空きがない場合
    // リーク防止のため delete
    delete m;
}

// createMateria:
// 型名にマッチする原本の clone を返す
// 原本はそのまま保持 (コピーを渡すだけ)
// 呼び出し側が delete 責任を持つ
AMateria* MateriaSource::createMateria(
    std::string const&amp; type
) {
    for (int i = 0; i &lt; 4; i++) {
        if (_learned[i]
            &amp;&amp; _learned[i]-&gt;getType()
               == type)
            // プロトタイプパターン
            return _learned[i]-&gt;clone();
    }
    return 0;   // 見つからなければ NULL
}
